#!/usr/bin/env node
/**
 * VEXTREME - lib/build-page-health.js
 *
 * Builds one deterministic page-capability projection for Archives and the
 * Terrain Map. It joins existing registries and audits; it does not introduce
 * a second hand-maintained page inventory.
 *
 * LATTICE:BEGIN — generated by lib/build-lattice-headers.js from docs/lattice-map.json. Do not hand-edit; edit the JSON and regenerate.
 *   role      : joins existing page registries, runtime audits, localization identity, analysis, and screenshot evidence into one deterministic per-page capability projection
 *   reads     : pages∕*.html (runtime tags, data-i18n bindings, authored theme styles)
 *               data/nodes.json (arc placement)
 *               data/strings/compiled/manifest.json (translation coverage)
 *               data/analysis-index.json (analysis indexing)
 *               dist∕*.js (God Script FAB and analysis delivery)
 *               docs/screenshots∕*.png (evidence presence)
 *               lib/audit-pages.js (page inventory and God Script wiring)
 *               lib/audit-nav.js (navigation classification)
 *               lib/audit-fab.js (theme ownership and opt-out classification)
 *   writes    : data/page-health.json
 *   loaded-by : manual run: node lib/build-page-health.js
 *               .github/workflows/build-index.yml (before Archives and Terrain)
 *               tests/helpers/prereqs.js
 *               tests/44-page-health.test.js
 *   tested-by : tests/44-page-health.test.js
 *
 *   CHANGE MAP — if you touch X here, also check:
 *     data/page-health.json schema changed:
 *       - lib/build-archives.js (page-health badges and summary)
 *       - lib/build-terrain-map.js (content node status and capability payload)
 *       - pages/terrain-map.html (content detail panel)
 *       - tests/44-page-health.test.js
 *     health severity rules changed:
 *       - Archives summary counts and Terrain content status colors both change
 * LATTICE:END
 */

'use strict';

const fs = require('fs');
const path = require('path');
const { getPageSlugs, isWiredToGodScript } = require('./audit-pages');
const { getNavReport } = require('./audit-nav');
const { managesOwnDataTheme, hasThemeOptOut } = require('./audit-fab');

const ROOT = path.join(__dirname, '..');
const PAGES_DIR = path.join(ROOT, 'pages');
const DIST_DIR = path.join(ROOT, 'dist');
const SCREENSHOTS_DIR = path.join(ROOT, 'docs', 'screenshots');
const OUT_PATH = path.join(ROOT, 'data', 'page-health.json');

function readJson(relPath, fallback) {
  const file = path.join(ROOT, relPath);
  return fs.existsSync(file) ? JSON.parse(fs.readFileSync(file, 'utf8')) : fallback;
}

function pageI18nKeys(html) {
  const keys = new Set();
  const re = /\bdata-i18n=["']([^"']+)["']/g;
  let match;
  while ((match = re.exec(html))) keys.add(match[1]);
  return [...keys].sort();
}

function languageCoverage(keys, manifest) {
  const languages = new Set(['en']);
  for (const key of keys) {
    const entry = manifest[key];
    for (const lang of (entry && entry.langs) || []) languages.add(lang);
  }

  const coverage = {};
  for (const lang of [...languages].sort()) {
    const translated = keys.filter((key) => manifest[key] && manifest[key].langs.includes(lang)).length;
    coverage[lang] = {
      translated,
      total: keys.length,
      state: keys.length === 0 ? 'none' : (translated === keys.length ? 'full' : (translated > 0 ? 'partial' : 'none')),
    };
  }
  return coverage;
}

function screenshotLanguages(slug, files) {
  const prefix = `${slug}-`;
  return files
    .filter((file) => file.startsWith(prefix) && file.endsWith('.png'))
    .map((file) => file.slice(prefix.length, -4))
    .filter((lang) => /^[a-z]{2,}$/.test(lang))
    .sort();
}

function metaDescriptionText(html) {
  const match = html.match(/<meta\s+name=["']description["']\s+content=["']([^"']*)["']/i);
  return match ? match[1].trim() : '';
}

function hasVisibleThemeStyles(html) {
  return /\[data-theme=["']?(?:light|dark)["']?\]/.test(html) ||
    /:root\[data-theme=["']?(?:light|dark)["']?\]/.test(html) ||
    /prefers-color-scheme\s*:\s*(?:light|dark)/.test(html);
}

function fabDelivery(html, distJs, wired) {
  const shell = /lib\/shell\.js/.test(html);
  const disabled = /\bfab\s*:\s*false/.test(html);
  const handAuthored = /widgets\/[^"']*fab[^"']*\.js/.test(html);
  const godScriptFab = wired && (distJs.includes('feature: spiral-fab') || distJs.includes('vex-fab.js'));
  if (disabled) return 'disabled';
  if (shell) return 'shell';
  if (godScriptFab) return 'god-script';
  if (handAuthored) return 'page-owned';
  return 'missing';
}

function computeHealth(page) {
  const blockers = [];
  const gaps = [];
  if (!page.navigation.navigable) blockers.push('isolated');
  if (page.fab.delivery === 'missing') gaps.push('fab');
  if (page.placement.state !== 'sorted') gaps.push(page.placement.state);
  if (page.identity.keyCount === 0) gaps.push('identity');
  if (page.evidence.screenshotLanguages.length === 0) gaps.push('screenshot');
  if (page.theme.control !== 'none' && !page.theme.visibleStyles) gaps.push('theme-effect');
  return {
    state: blockers.length ? 'critical' : (gaps.length ? 'attention' : 'healthy'),
    blockers,
    gaps,
  };
}

function buildPageHealth(inputs) {
  const nodesBySlug = Object.fromEntries((inputs.nodes || []).map((node) => [node.slug, node]));
  const navBySlug = Object.fromEntries((inputs.navRows || []).map((row) => [row.slug, row]));
  const pages = {};

  for (const slug of inputs.pageSlugs.slice().sort()) {
    const html = inputs.htmlBySlug[slug] || '';
    const distJs = inputs.distBySlug[slug] || '';
    const node = nodesBySlug[slug];
    const keys = pageI18nKeys(html);
    const wired = Boolean(inputs.wiredBySlug[slug]);
    const nav = navBySlug[slug] || { staticHubLinks: 0, hasShellJs: false, hasFabNav: false, navigable: false };
    const themeOwned = managesOwnDataTheme(html);
    const themeOptOut = hasThemeOptOut(html);

    const page = {
      slug,
      title: (node && node.title) || slug,
      placement: {
        state: !node ? 'uncurated' : ((node.arcKeys || []).length ? 'sorted' : 'unsorted'),
        arcKeys: (node && node.arcKeys) || [],
      },
      runtime: {
        shell: nav.hasShellJs,
        godScript: wired,
      },
      navigation: {
        navigable: nav.navigable,
        staticHubLinks: nav.staticHubLinks,
        shell: nav.hasShellJs,
        fab: nav.hasFabNav,
      },
      fab: { delivery: fabDelivery(html, distJs, wired) },
      theme: {
        control: themeOwned ? 'page-owned' : (nav.hasShellJs && !themeOptOut ? 'shared' : 'none'),
        visibleStyles: hasVisibleThemeStyles(html),
      },
      identity: {
        keyCount: keys.length,
        languages: languageCoverage(keys, inputs.manifest || {}),
      },
      analysis: {
        indexed: Boolean(inputs.analysisPages && inputs.analysisPages[slug]),
        control: /fab-analysis\.js/.test(html) || /feature:\s*analysis/.test(distJs),
      },
      evidence: {
        screenshotLanguages: screenshotLanguages(slug, inputs.screenshotFiles || []),
      },
      discovery: {
        metaDescription: metaDescriptionText(html),
      },
    };
    page.health = computeHealth(page);
    pages[slug] = page;
  }

  const rows = Object.values(pages);
  return {
    schemaVersion: 1,
    summary: {
      total: rows.length,
      healthy: rows.filter((page) => page.health.state === 'healthy').length,
      attention: rows.filter((page) => page.health.state === 'attention').length,
      critical: rows.filter((page) => page.health.state === 'critical').length,
      sorted: rows.filter((page) => page.placement.state === 'sorted').length,
      withFab: rows.filter((page) => page.fab.delivery !== 'missing' && page.fab.delivery !== 'disabled').length,
      withIdentity: rows.filter((page) => page.identity.keyCount > 0).length,
      withScreenshots: rows.filter((page) => page.evidence.screenshotLanguages.length > 0).length,
      withMetaDescription: rows.filter((page) => page.discovery.metaDescription).length,
    },
    pages,
  };
}

function loadInputs() {
  const pageSlugs = getPageSlugs();
  const htmlBySlug = {};
  const distBySlug = {};
  const wiredBySlug = {};
  for (const slug of pageSlugs) {
    htmlBySlug[slug] = fs.readFileSync(path.join(PAGES_DIR, `${slug}.html`), 'utf8');
    const distPath = path.join(DIST_DIR, `vextreme-${slug}.js`);
    distBySlug[slug] = fs.existsSync(distPath) ? fs.readFileSync(distPath, 'utf8') : '';
    wiredBySlug[slug] = isWiredToGodScript(slug);
  }
  return {
    pageSlugs,
    htmlBySlug,
    distBySlug,
    wiredBySlug,
    navRows: getNavReport().rows,
    nodes: readJson('data/nodes.json', []),
    manifest: readJson('data/strings/compiled/manifest.json', {}),
    analysisPages: readJson('data/analysis-index.json', {}).pages || {},
    screenshotFiles: fs.existsSync(SCREENSHOTS_DIR) ? fs.readdirSync(SCREENSHOTS_DIR) : [],
  };
}

if (require.main === module) {
  const result = buildPageHealth(loadInputs());
  fs.writeFileSync(OUT_PATH, JSON.stringify(result, null, 2) + '\n');
  console.log(`[build-page-health] ${result.summary.total} pages: ${result.summary.healthy} healthy, ${result.summary.attention} attention, ${result.summary.critical} critical`);
  console.log(`  output: ${OUT_PATH}`);
}

module.exports = {
  pageI18nKeys,
  languageCoverage,
  screenshotLanguages,
  hasVisibleThemeStyles,
  metaDescriptionText,
  fabDelivery,
  computeHealth,
  buildPageHealth,
  loadInputs,
};

// [VXG RealForever]
